Rule.Source:
 
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.Application;
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.object.ProvisioningPlan.AccountRequest;
  import sailpoint.tools.Util;
  import connector.common.JsonUtil;
  import connector.common.Util;
  import sailpoint.api.IdentityService;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;
  Log logger = LogFactory.getLog("rule.Ascension.Voalte.Update.BeforeOperation");

  IdentityService idService = new IdentityService(context);
  Identity identity;
  List applinks = new ArrayList();
  List requestedClientAccess=new ArrayList();
  List accessList = new ArrayList();
  Link appLink;
  String nativeID = null;
  Long userIdVal=0;

  String sessionVal = createSession();
  String sessionToken = "VoalteSession "+sessionVal;

  try{
    if (provisioningPlan != null) {
      Identity identity = provisioningPlan.getIdentity();

      if(null != application && null != identity && !Util.isEmpty((appLinks = idService.getLinks( identity, application)))){	
        appLink = appLinks.get(0);
      }

      for (AccountRequest accReq : Util.iterate(provisioningPlan.getAccountRequests())) {
        if(accReq!=null) {
          nativeID = accReq.getNativeIdentity();
          for (ProvisioningPlan.AttributeRequest attReq : Util.iterate(accReq.getAttributeRequests())) {
            if(attReq!=null) {
              String attrName = attReq.getName();
              if (attrName != null && "client_type_access".equalsIgnoreCase(attrName) && null != attReq.getValue()) {
                if(attReq.getValue() instanceof String){
                  requestedClientAccess.add(attReq.getValue());
                }else{
                  requestedClientAccess = attReq.getValue();
                }
              }
            }
          }
        }
      }

      Map body = requestEndPoint.getBody();
      String jsonBody = (String) body.get("jsonBody");
      Map jsonMap = JsonUtil.toMap(jsonBody);

      if (jsonMap != null) {
        Object accessType = jsonMap.get("client_type_access");

        if(null!= appLink && !Util.isEmpty(appLink.getAttribute("client_type_access"))){
          if(appLink.getAttribute("client_type_access") instanceof String){
            accessList.add(appLink.getAttribute("client_type_access"));
          }else{
            accessList.addAll(appLink.getAttribute("client_type_access"));
          }
        }

        if(Util.isEmpty(accessList)){
          accessList.add("voalte_messenger");
        }

        if(requestedClientAccess!=null && !requestedClientAccess.isEmpty() && !accessList.contains("voalte_me") && requestedClientAccess.contains("voalte_me")){
          accessList.add("voalte_me");
        }

        jsonMap.remove("client_type_access");
        jsonMap.put("client_type_access", accessList);

        String finalBody = JsonUtil.render(jsonMap);
        body.put("jsonBody", finalBody);
        requestEndPoint.setBody(body);
      }

      Map headerMap = requestEndPoint.getHeader();
      headerMap.put("Authorization",sessionToken);
      requestEndPoint.setHeader(headerMap);

      if(Util.isNullOrEmpty(nativeID)){
        if(Util.isNotNullOrEmpty(identity.getAttribute("samAccountName"))){
          nativeID = identity.getAttribute("samAccountName");
        }
        else{
          nativeID =  identity.getName();
        }
      }

      String raw_Response = getUserDetails(nativeID);

      Map returnMap=new HashMap();
      List valueList=new ArrayList();
      if(raw_Response !=null){
        JSONParser parse = new JSONParser();
        JSONArray mainObj = (JSONArray )parse.parse(raw_Response);
        if(null != mainObj) {
          for(org.json.simple.JSONObject currentIdentifier :mainObj ) {
            userIdVal=currentIdentifier.get("id");
          }
        }
        
        Map map = requestEndPoint.getBody();

        String body=null;
        if (map!=null && map.get("jsonBody")!=null){
          String contextURL="users/"+userIdVal;
          String oldCtxURL=requestEndPoint.getContextUrl();
          requestEndPoint.setContextUrl(contextURL);
          String fullUrl=requestEndPoint.getFullUrl();
          String fullUrlModi=fullUrl.replace(oldCtxURL,contextURL);
          requestEndPoint.setFullUrl(fullUrlModi);                             
        }
      }
    }
  }catch(Exception e) {
    logger.error("Exception in NetSuite aggregation before rule "+e.getMessage());
  }

  return requestEndPoint;
